cd /tmp/sv-e9f562d47f2e4d7f8e01d90e63dc5921/advanced-multi-complexity && dotnet package list --format json 2>/dev/null | cat > after-cpm-packages.json && python3 -c "
import json

baseline = json.load(open('baseline-packages.json'))
after = json.load(open('after-cpm-packages.json'))

def get_packages(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            tfm = fw['framework']
            for pkg in fw.get('topLevelPackages', []):
                key = (name, tfm, pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = get_packages(baseline)
a = get_packages(after)

all_keys = sorted(set(b.keys()) | set(a.keys()))

print('=== CHANGES ===')
changes = False
for k in all_keys:
    bv = b.get(k)
    av = a.get(k)
    if bv != av:
        changes = True
        proj, tfm, pkg = k
        if bv and av:
            print(f'  {proj} ({tfm}) | {pkg} | {bv} -> {av} | Aligned to highest')
        elif not bv:
            print(f'  {proj} ({tfm}) | {pkg} | (new) -> {av} | Added')
        else:
            print(f'  {proj} ({tfm}) | {pkg} | {bv} -> (removed) | Removed')
if not changes:
    print('  No changes')

print()
print('=== UNCHANGED ===')
for k in all_keys:
    bv = b.get(k)
    av = a.get(k)
    if bv == av:
        proj, tfm, pkg = k
        print(f'  {proj} ({tfm}) | {pkg} | {bv}')
"

